using Contoso.Text;

namespace Contoso.Text.Tests;

[TestClass]
public sealed class StringFormatterTests
{
    private readonly StringFormatter _formatter = new();

    // --- FormatPhoneNumber ---

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_StartsWithAreaCode()
    {
        var result = _formatter.FormatPhoneNumber("5551234567");

        Assert.StartsWith("(555)", result);
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_EndsWithLastFour()
    {
        var result = _formatter.FormatPhoneNumber("5551234567");

        Assert.EndsWith("4567", result);
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_ContainsDash()
    {
        var result = _formatter.FormatPhoneNumber("5551234567");

        Assert.Contains("-", result);
    }

    [TestMethod]
    public void FormatPhoneNumber_ValidDigits_ReturnsFullFormat()
    {
        var result = _formatter.FormatPhoneNumber("5551234567");

        Assert.AreEqual("(555) 123-4567", result);
    }

    [TestMethod]
    [DataRow("")]
    [DataRow("123")]
    [DataRow("12345678901")]
    public void FormatPhoneNumber_InvalidLength_ThrowsArgumentException(string digits)
    {
        Assert.ThrowsExactly<ArgumentException>(() => _formatter.FormatPhoneNumber(digits));
    }

    [TestMethod]
    public void FormatPhoneNumber_Null_ThrowsArgumentNullException()
    {
        Assert.ThrowsExactly<ArgumentNullException>(() => _formatter.FormatPhoneNumber(null!));
    }

    // --- BuildGreeting ---

    [TestMethod]
    public void BuildGreeting_WithDefaultTitle_StartsWithDearMr()
    {
        var result = _formatter.BuildGreeting("Smith");

        Assert.StartsWith("Dear Mr.", result);
    }

    [TestMethod]
    public void BuildGreeting_WithName_EndsWithComma()
    {
        var result = _formatter.BuildGreeting("Smith");

        Assert.EndsWith(",", result);
    }

    [TestMethod]
    public void BuildGreeting_WithName_ContainsName()
    {
        var result = _formatter.BuildGreeting("Johnson");

        Assert.Contains("Johnson", result);
    }

    [TestMethod]
    public void BuildGreeting_WithCustomTitle_StartsWithTitle()
    {
        var result = _formatter.BuildGreeting("Doe", "Dr.");

        Assert.StartsWith("Dear Dr.", result);
    }

    [TestMethod]
    public void BuildGreeting_WithCustomTitle_ReturnsFullGreeting()
    {
        var result = _formatter.BuildGreeting("Doe", "Dr.");

        Assert.AreEqual("Dear Dr. Doe,", result);
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public void BuildGreeting_InvalidName_ThrowsArgumentException(string? name)
    {
        Assert.ThrowsExactly<ArgumentException>(() => _formatter.BuildGreeting(name!));
    }

    // --- GenerateSlug ---

    [TestMethod]
    public void GenerateSlug_SimpleTitle_ReturnsLowercaseSlug()
    {
        var result = _formatter.GenerateSlug("Hello World");

        Assert.AreEqual("hello-world", result);
    }

    [TestMethod]
    public void GenerateSlug_TitleWithSpecialChars_ContainsOnlyValidChars()
    {
        var result = _formatter.GenerateSlug("C# is Great!!");

        Assert.MatchesRegex(@"^[a-z0-9\-]+$", result);
    }

    [TestMethod]
    public void GenerateSlug_TitleStartingWithSpecialChars_DoesNotStartWithDash()
    {
        var result = _formatter.GenerateSlug("!!Hello");

        Assert.StartsWith("hello", result);
    }

    [TestMethod]
    public void GenerateSlug_TitleEndingWithSpecialChars_DoesNotEndWithDash()
    {
        var result = _formatter.GenerateSlug("Hello!!");

        Assert.EndsWith("hello", result);
    }

    [TestMethod]
    [DataRow("My Blog Post", "my-blog-post")]
    [DataRow("  Trimmed  ", "trimmed")]
    [DataRow("ALL CAPS TITLE", "all-caps-title")]
    public void GenerateSlug_VariousTitles_ReturnsExpectedSlug(string title, string expected)
    {
        var result = _formatter.GenerateSlug(title);

        Assert.AreEqual(expected, result);
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public void GenerateSlug_InvalidTitle_ThrowsArgumentException(string? title)
    {
        Assert.ThrowsExactly<ArgumentException>(() => _formatter.GenerateSlug(title!));
    }

    // --- FormatCurrency ---

    [TestMethod]
    public void FormatCurrency_DefaultSymbol_StartsWithDollarSign()
    {
        var result = _formatter.FormatCurrency(9.99m);

        Assert.StartsWith("$", result);
    }

    [TestMethod]
    public void FormatCurrency_CustomSymbol_StartsWithSymbol()
    {
        var result = _formatter.FormatCurrency(19.99m, "€");

        Assert.StartsWith("€", result);
    }

    [TestMethod]
    public void FormatCurrency_WholeNumber_EndsWithTwoDecimalPlaces()
    {
        var result = _formatter.FormatCurrency(100m);

        Assert.EndsWith(".00", result);
    }

    [TestMethod]
    [DataRow(0.0, "$0.00")]
    [DataRow(9.99, "$9.99")]
    [DataRow(1234.5, "$1234.50")]
    public void FormatCurrency_VariousAmounts_ReturnsExpectedFormat(double amount, string expected)
    {
        var result = _formatter.FormatCurrency((decimal)amount);

        Assert.AreEqual(expected, result);
    }
}

